package be.schaubroeck.lpb.rkm.rekenmotor;

import be.schaubroeck.lpb.rkm.rekenmotor.bv.BvTools;
import be.schaubroeck.lpb.rkm.rekenmotor.util.HashMoneyMap;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.MoneyMap;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenTools;
import be.schaubroeck.lpb.rkm.rekenmotor.util.verdeler.BedragVerdelerFactory;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.enumtypes.DmfapplWnkengetal;
import be.schaubroeck.lpb.tools.enumtypes.LnedefRegBv;
import be.schaubroeck.lpb.tools.enumtypes.Pensioenstelsel;
import be.schaubroeck.lpb.tools.enumtypes.WerkgeversCategorie;
import com.google.common.collect.ArrayListMultimap;
import com.google.common.collect.Multimap;
import lombok.EqualsAndHashCode;

import java.util.Collection;
import java.util.Set;
import java.util.TreeSet;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBbKey.BELASTBAAR_ACHTERSTAL_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBbKey.BELASTBAAR_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBbKey.DIFF_BELASTBAAR_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.LOONELEMENT_MANAGER_KEY;

public class BerekenBelastbaarAchterstal extends AbstractRekenCommand {

    @Override
    protected boolean execute(RekenContext context) {
        RekenContext preBerekeningContext = context.getUnchecked(RekenTools.bepaalVorigeBerekeningType(context));
        if (!preBerekeningContext.isEmpty()) {
            vormAchterstalBelastbaar(context, preBerekeningContext);
        }

        return CONTINUE_PROCESSING;
    }

    private void vormAchterstalBelastbaar(RekenContext context, RekenContext preBerekeningContext) {
        LoonElementManager prevManager = preBerekeningContext.getUnchecked(LOONELEMENT_MANAGER_KEY);
        Collection<LoonElement> prevLoonElementen = prevManager.getPersoonsElementen();

        LoonElementManager currManager = context.getUnchecked(LOONELEMENT_MANAGER_KEY);
        Collection<LoonElement> currLoonElementen = currManager.getPersoonsElementen();

        vormAchterstalBelastbaar(currLoonElementen, prevLoonElementen);
    }

    public void vormAchterstalBelastbaar(Collection<LoonElement> currLoonElementen, Collection<LoonElement> prevLoonElementen) {
        //bereken per loonelement de diff belastbaar met de corresponderende rekenlijn in de vorige toestand
        Multimap<AchterstalKey, LoonElement> preSleutelMap = vormSleutelMap(prevLoonElementen);
        Multimap<AchterstalKey, LoonElement> currSleutelMap = vormSleutelMap(currLoonElementen);
        for (AchterstalKey key : currSleutelMap.keySet()) {
            Collection<LoonElement> elementen = currSleutelMap.get(key);
            Money currBb = RekenTools.getSomProperty(BELASTBAAR_KEY, elementen);
            Collection<LoonElement> preElementen = preSleutelMap.get(key);
            Money preBb = RekenTools.getSomProperty(BELASTBAAR_KEY, preElementen);
            Money diffBb = currBb.subtract(preBb).max(Money.ZERO);
            BedragVerdelerFactory.verdeelBedragVolgensBasisPut(DIFF_BELASTBAAR_KEY, diffBb, BELASTBAAR_KEY, currBb, elementen);
        }

        Multimap<LnedefRegBv, LoonElement> prevRegimeMap = vormRegimeMap(prevLoonElementen);
        Multimap<LnedefRegBv, LoonElement> currRegimeMap = vormRegimeMap(currLoonElementen);
        MoneyMap<LnedefRegBv> verlorenMap = new HashMoneyMap<>();
        Set<LnedefRegBv> regimes = new TreeSet<>();
        regimes.addAll(prevRegimeMap.keySet());
        regimes.addAll(currRegimeMap.keySet());

        for (LnedefRegBv regime : regimes) {
            Collection<LoonElement> prevRegimeElementen = prevRegimeMap.get(regime);
            Collection<LoonElement> currRegimeElementen = currRegimeMap.get(regime);

            //Totaal belastbaar voor de hele persoon in de vorige toestand
            Money prevBelastbaar = RekenTools.getSomProperty(BELASTBAAR_KEY, prevRegimeElementen);

            //Totaal belastbaar voor de hele persoon in de huidige berekening
            Money currBelastbaar = RekenTools.getSomProperty(BELASTBAAR_KEY, currRegimeElementen);

            Money achterstalBelastbaar = currBelastbaar.subtract(prevBelastbaar);

            Money somDiffBb = RekenTools.getSomProperty(DIFF_BELASTBAAR_KEY, currRegimeElementen);

            if (achterstalBelastbaar.signum() < 0 && somDiffBb.signum() == 0) {
                LnedefRegBv paragon = mapToParagonAchterstalRegime(regime);
                verlorenMap.addToMoney(paragon, achterstalBelastbaar);
            }
            achterstalBelastbaar = achterstalBelastbaar.max(Money.ZERO);

            //Verdeel achterstalBelastbaar volgen verdeelsleutel (diffBelastbaar/somDiffBelastbaar)
            BedragVerdelerFactory.verdeelBedragVolgensBasisPut(BELASTBAAR_ACHTERSTAL_KEY, achterstalBelastbaar, DIFF_BELASTBAAR_KEY, somDiffBb, currRegimeElementen);
        }

        Multimap<LnedefRegBv, LoonElement> typeMap = vormTypeBvAchterstalMap(currLoonElementen);
        for (LnedefRegBv regime : verlorenMap.keySet()) {
            LnedefRegBv paragon = mapToParagonAchterstalRegime(regime);
            Collection<LoonElement> elementen = typeMap.get(paragon);
            Money somDiffBb = RekenTools.getSomProperty(DIFF_BELASTBAAR_KEY, elementen);
            if (somDiffBb.signum() != 0) {
                Money verloren = verlorenMap.get(regime);
                Money belastbaarAchterstal = RekenTools.getSomProperty(BELASTBAAR_ACHTERSTAL_KEY, elementen);
                if (verloren.signum() < 0 && belastbaarAchterstal.signum() >= 0) {
                    verloren = verloren.max(belastbaarAchterstal.negate());
                }
                BedragVerdelerFactory.verdeelBedragVolgensBasisAdd(BELASTBAAR_ACHTERSTAL_KEY, verloren, DIFF_BELASTBAAR_KEY, somDiffBb, elementen);
            }
        }

    }

    private Multimap<LnedefRegBv, LoonElement> vormRegimeMap(Collection<LoonElement> loonElementen) {
        Multimap<LnedefRegBv, LoonElement> regimeMap = ArrayListMultimap.create();
        for (LoonElement element : loonElementen) {
            regimeMap.put(element.getRegimeBv(), element);
        }
        return regimeMap;
    }

    private Multimap<LnedefRegBv, LoonElement> vormTypeBvAchterstalMap(Collection<LoonElement> loonElementen) {
        Multimap<LnedefRegBv, LoonElement> regimeMap = ArrayListMultimap.create();
        for (LoonElement element : loonElementen) {
            LnedefRegBv achterstalKey = element.getRegimeBv();
            achterstalKey = mapToParagonAchterstalRegime(achterstalKey);
            regimeMap.put(achterstalKey, element);
        }
        return regimeMap;
    }

    //TODO is dit correct? volledig? wat zijn de verschillend achterstal belastbaar hoopjes?
    private LnedefRegBv mapToParagonAchterstalRegime(LnedefRegBv regime) {
        LnedefRegBv paragon = regime;
        if (BvTools.isRegimeAchterstal(regime)) {
            paragon = LnedefRegBv.VD_BV_10_BZ___GB;
        } else if (regime == LnedefRegBv.VD_BV_10_UKAG_GB) {
            paragon = LnedefRegBv.VD_BV_10_UKZI_GB;
        }
        return paragon;
    }

    private Multimap<AchterstalKey, LoonElement> vormSleutelMap(Collection<LoonElement> loonElementen) {
        Multimap<AchterstalKey, LoonElement> sleutelMap = ArrayListMultimap.create();
        for (LoonElement element : loonElementen) {
            sleutelMap.put(new AchterstalKey(element), element);
        }
        return sleutelMap;
    }

    @EqualsAndHashCode
    private static class AchterstalKey {

        private final int opdrachtid;
        private final int categorie;
        private final WerkgeversCategorie wgcategorie;
        private final DmfapplWnkengetal wnkengetal;
        private final Pensioenstelsel pensioenstelsel;
        private final int akeId;
        private final Integer referentieJaar;

        AchterstalKey(LoonElement element) {
            Opper opper = element.getOpper();
            AardKodeExtensie looncode = element.getAardKodeExtensie();
            this.opdrachtid = opper.getOpdracht().getId();
            this.categorie = opper.getRszppo().getCategorie().getCode();
            this.wgcategorie = opper.getRszppo().getWerkgeversCategorie();
            this.wnkengetal = opper.getRszppo().getWerknemersKengetal();
            this.pensioenstelsel = opper.getRszppo().getPensioenStelsel();
            this.akeId = looncode.getId();
            this.referentieJaar = element.getReferentieJaar();
        }
    }
}
